        <div class="text center xxl-spacing-top max-width-6-desktop-dark xxl-spacing-bottom text-block con-block has-bg" data-block-status="loaded" data-block="" style="background: rgb(30, 30, 30);">
          
          <div class="foreground">
            <div>
              <h2 id="not-sure-which-apps-are-best-for-your-team" class="heading-xl">Not sure which apps are best for your team?</h2>
              <p class="body-m">We can help in just a few clicks.</p>
              <div class="cta-container"><p class="body-m action-area"><a href="/creativecloud/plan-recommender/quiz/" aria-label="Creative Cloud Plan Recommender Quiz" class="con-button outline">Get started</a></p></div>
